import{_ as a,p as e,q as n,a1 as s}from"./framework-5866ffd3.js";const i={},d=s(`<h1 id="nologin" tabindex="-1"><a class="header-anchor" href="#nologin" aria-hidden="true">#</a> nologin</h1><p>拒绝用户登录系统</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>nologin命令</strong> 可以实现礼貌地拒绝用户登录系统，同时给出信息。如果尝试以这类用户登录，就在log里添加记录，然后在终端输出This account is currently not available信息，就是这样。一般设置这样的帐号是给启动服务的账号所用的，这只是让服务启动起来，但是不能登录系统。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>nologin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>Linux禁止用户登录：</p><p>禁止用户登录后，用户不能登录系统，但可以登录ftp、SAMBA等。我们在Linux下做系统维护的时候，希望个别用户或者所有用户不能登录系统，保证系统在维护期间正常运行。这个时候我们就要禁止用户登录。</p><p>1、禁止个别用户登录，比如禁止lynn用户登录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">passwd</span> <span class="token parameter variable">-l</span> lynn
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>这就话的意思是锁定lynn用户，这样该用户就不能登录了。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">passwd</span> <span class="token parameter variable">-u</span> lynn
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>上面是对锁定的用户lynn进行解锁，用户可登录了。</p><p>2、我们通过修改<code>/etc/passwd</code>文件中用户登录的shell</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">vi</span> /etc/passwd
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>更改为：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>lynn:x:500:500::/home/lynn:/sbin/nologin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>该用户就无法登录了。</p><p>3、禁止所有用户登录。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">touch</span> /etc/nologin
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>除root以外的用户不能登录了。</p>`,22),l=[d];function r(c,o){return e(),n("div",null,l)}const p=a(i,[["render",r],["__file","nologin.html.vue"]]);export{p as default};
